    content:
      "/**\n * Game UI Components\n *\n * Accessible, mobile-first components for building game interfaces\n *\n * Component Architecture:\n * - Base components (Card, Hand, PlayArea) are presentational and receive data as props\n * - Connected components (ConnectedCard) use hooks to fetch data from context\n * - Use base components for fixtures/testing or manual data management\n * - Use connected components when RuntimeContext is set up\n */\n\n// Presentational components (no hooks, receive data as props)\nexport { Card, type CardProps, type CardItem } from './Card';\nexport { Hand, type HandProps } from './Hand';\nexport { PlayArea, type PlayAreaProps } from './PlayArea';\n\n// Connected components (use hooks, require RuntimeContext)\nexport { ConnectedCard, type ConnectedCardProps } from './ConnectedCard';\n\n// Other UI components\nexport { PlayerInfo, type PlayerInfoProps } from './PlayerInfo';\nexport { GameSkeleton, type GameSkeletonProps } from './GameSkeleton';\nexport {\n  ToastProvider,\n  useToast,\n  type Toast,\n  type ToastType,\n} from './Toast';\nexport { ErrorBoundary, type ErrorBoundaryProps } from './ErrorBoundary';\nexport { PluginRuntime, type PluginRuntimeProps } from './PluginRuntime';\nexport { PlayerSwitcher, type PlayerSwitcherProps } from './PlayerSwitcher';\nexport {\n  HistoryNavigator,\n  type HistoryNavigatorProps,\n} from './HistoryNavigator';\nexport {\n  Drawer,\n  DrawerPortal,\n  DrawerOverlay,\n  DrawerTrigger,\n  DrawerClose,\n  DrawerContent,\n  DrawerHeader,\n  DrawerFooter,\n  DrawerTitle,\n  DrawerDescription,\n} from './Drawer';\n\n// Game UI primitives (SDK v0.1.0+)\nexport {\n  ResourceCounter,\n  type ResourceCounterProps,\n  type ResourceDisplayConfig,\n} from './ResourceCounter';\nexport {\n  CostDisplay,\n  type CostDisplayProps,\n  type ResourceDefinition,\n} from './CostDisplay';\nexport { ActionButton, type ActionButtonProps } from './ActionButton';\nexport {\n  ActionPanel,\n  ActionGroup,\n  type ActionPanelProps,\n  type ActionGroupProps,\n} from './ActionPanel';\nexport { DiceRoller, type DiceRollerProps } from './DiceRoller';\nexport { PhaseIndicator, type PhaseIndicatorProps } from './PhaseIndicator';\nexport {\n  GameEndDisplay,\n  type GameEndDisplayProps,\n  type PlayerScore,\n} from './GameEndDisplay';\n\n// Board primitives (SDK v0.2.0+)\nexport {\n  NetworkGraph,\n  type NetworkGraphProps,\n  type NetworkNode,\n  type NetworkEdge,\n  type NetworkPiece,\n} from './board/NetworkGraph';\n\nexport {\n  ZoneMap,\n  type ZoneMapProps,\n  type ZoneDefinition,\n  type ZonePiece,\n  type ZoneShape,\n  type ZoneHighlightType,\n} from './board/ZoneMap';\n\nexport {\n  TrackBoard,\n  type TrackBoardProps,\n  type TrackSpace,\n  type TrackPiece,\n} from './board/TrackBoard';\n\nexport {\n  SlotSystem,\n  type SlotSystemProps,\n  type SlotDefinition,\n  type SlotOccupant,\n} from './board/SlotSystem';\n\nexport {\n  SquareGrid,\n  DefaultGridCell,\n  DefaultGridPiece,\n  DefaultChessPiece,\n  toAlgebraic,\n  toNumeric,\n  type SquareGridProps,\n  type GridCell,\n  type GridPiece,\n  type DefaultGridCellProps,\n  type DefaultGridPieceProps,\n  type DefaultChessPieceProps,\n} from './board/SquareGrid';\n\nexport {\n  HexGrid,\n  hexUtils,\n  DefaultHexTile,\n  DefaultHexEdge,\n  DefaultHexVertex,\n  type HexGridProps,\n  type HexOrientation,\n  type EdgePosition,\n  type DefaultHexTileProps,\n  type DefaultHexEdgeProps,\n  type DefaultHexVertexProps,\n} from './board/HexGrid';\n",
    checksumSha256:
      "c1f2215355802c6d885e5b3a4e66d8e03d086a39d774b2a9886683ef20215312",
