    content:
      '/**\n * Toast notification component\n *\n * Displays temporary notifications for game events\n */\n\nimport { motion, AnimatePresence } from "framer-motion";\nimport { clsx } from "clsx";\nimport { X, CheckCircle, AlertCircle, Info, AlertTriangle } from "lucide-react";\nimport {\n  createContext,\n  useContext,\n  useState,\n  useCallback,\n  type ReactNode,\n} from "react";\n\nexport type ToastType = "success" | "error" | "info" | "warning";\n\nexport interface Toast {\n  id: string;\n  type: ToastType;\n  message: string;\n  duration?: number;\n}\n\ninterface ToastContextValue {\n  toasts: Toast[];\n  show: (message: string, type?: ToastType, duration?: number) => void;\n  dismiss: (id: string) => void;\n  success: (message: string, duration?: number) => void;\n  error: (message: string, duration?: number) => void;\n  info: (message: string, duration?: number) => void;\n  warning: (message: string, duration?: number) => void;\n}\n\nconst ToastContext = createContext<ToastContextValue | null>(null);\n\n/**\n * Toast provider component\n */\nexport function ToastProvider({ children }: { children: ReactNode }) {\n  const [toasts, setToasts] = useState<Toast[]>([]);\n\n  const show = useCallback(\n    (message: string, type: ToastType = "info", duration = 3000) => {\n      const id = `toast-${Date.now()}-${Math.random()}`;\n      const toast: Toast = { id, type, message, duration };\n\n      setToasts((prev) => [...prev, toast]);\n\n      if (duration > 0) {\n        setTimeout(() => {\n          setToasts((prev) => prev.filter((t) => t.id !== id));\n        }, duration);\n      }\n    },\n    [],\n  );\n\n  const dismiss = useCallback((id: string) => {\n    setToasts((prev) => prev.filter((t) => t.id !== id));\n  }, []);\n\n  const success = useCallback(\n    (message: string, duration?: number) => show(message, "success", duration),\n    [show],\n  );\n  const error = useCallback(\n    (message: string, duration?: number) => show(message, "error", duration),\n    [show],\n  );\n  const info = useCallback(\n    (message: string, duration?: number) => show(message, "info", duration),\n    [show],\n  );\n  const warning = useCallback(\n    (message: string, duration?: number) => show(message, "warning", duration),\n    [show],\n  );\n\n  return (\n    <ToastContext.Provider\n      value={{ toasts, show, dismiss, success, error, info, warning }}\n    >\n      {children}\n      <ToastContainer toasts={toasts} onDismiss={dismiss} />\n    </ToastContext.Provider>\n  );\n}\n\n/**\n * Hook to access toast functionality\n */\nexport function useToast() {\n  const context = useContext(ToastContext);\n  if (!context) {\n    throw new Error("useToast must be used within ToastProvider");\n  }\n  return context;\n}\n\n/**\n * Toast container component\n */\nfunction ToastContainer({\n  toasts,\n  onDismiss,\n}: {\n  toasts: Toast[];\n  onDismiss: (id: string) => void;\n}) {\n  return (\n    <div\n      className="fixed bottom-4 right-4 z-50 flex flex-col gap-2 pointer-events-none"\n      role="region"\n      aria-live="polite"\n      aria-label="Notifications"\n    >\n      <AnimatePresence>\n        {toasts.map((toast) => (\n          <ToastItem key={toast.id} toast={toast} onDismiss={onDismiss} />\n        ))}\n      </AnimatePresence>\n    </div>\n  );\n}\n\n/**\n * Individual toast item\n */\nfunction ToastItem({\n  toast,\n  onDismiss,\n}: {\n  toast: Toast;\n  onDismiss: (id: string) => void;\n}) {\n  const icons = {\n    success: CheckCircle,\n    error: AlertCircle,\n    info: Info,\n    warning: AlertTriangle,\n  };\n\n  const styles = {\n    success: {\n      bg: "bg-green-50",\n      border: "border-green-200",\n      text: "text-green-800",\n      icon: "text-green-600",\n    },\n    error: {\n      bg: "bg-red-50",\n      border: "border-red-200",\n      text: "text-red-800",\n      icon: "text-red-600",\n    },\n    info: {\n      bg: "bg-blue-50",\n      border: "border-blue-200",\n      text: "text-blue-800",\n      icon: "text-blue-600",\n    },\n    warning: {\n      bg: "bg-yellow-50",\n      border: "border-yellow-200",\n      text: "text-yellow-800",\n      icon: "text-yellow-600",\n    },\n  };\n\n  const Icon = icons[toast.type];\n  const style = styles[toast.type];\n\n  return (\n    <motion.div\n      className={clsx(\n        "pointer-events-auto flex items-start gap-3 p-4 rounded-lg border-2 shadow-lg backdrop-blur-sm",\n        "min-w-[280px] max-w-[400px]",\n        style.bg,\n        style.border,\n      )}\n      initial={{ opacity: 0, y: 20, scale: 0.9 }}\n      animate={{ opacity: 1, y: 0, scale: 1 }}\n      exit={{ opacity: 0, x: 100, scale: 0.9 }}\n      transition={{ type: "spring", stiffness: 300, damping: 25 }}\n      role="alert"\n      aria-live={toast.type === "error" ? "assertive" : "polite"}\n    >\n      <Icon\n        size={20}\n        className={clsx("flex-shrink-0 mt-0.5", style.icon)}\n        aria-hidden="true"\n      />\n\n      <p\n        className={clsx(\n          "flex-1 text-sm font-medium leading-relaxed",\n          style.text,\n        )}\n      >\n        {toast.message}\n      </p>\n\n      <button\n        type="button"\n        onClick={() => onDismiss(toast.id)}\n        className={clsx(\n          "flex-shrink-0 p-1 rounded transition-colors hover:bg-black/5",\n          style.text,\n        )}\n        aria-label="Close notification"\n      >\n        <X size={16} aria-hidden="true" />\n      </button>\n    </motion.div>\n  );\n}\n',
