      "/**\n * React hooks for plugin development.\n * These hooks provide access to game state and runtime functionality.\n */\n\nexport { useGameState } from './useGameState';\nexport { useGameSelector } from './useGameSelector';\nexport { useUIArgs } from './useUIArgs';\nexport { useCard, useCards } from './useCard';\nexport { useMyHand } from './useMyHand';\nexport { usePublicHands } from './usePublicHands';\nexport { useLobby } from './useLobby';\nexport { useAction, ValidationError } from './useAction';\nexport {\n  useGameNotifications,\n  useNotifications,\n  type GameNotificationHandlers,\n} from './useGameNotifications';\nexport { useMe } from './useMe';\nexport { usePlayerInfo } from './usePlayerInfo';\nexport {\n  useMyResources,\n  usePlayerResources,\n  useAllPlayerResources,\n  type PlayerResources,\n} from './useMyResources';\nexport {\n  usePluginRuntime,\n  type UsePluginRuntimeOptions,\n  type UsePluginRuntimeResult,\n} from './usePluginRuntime';\nexport { useHistory, useIsHost } from './useHistory';\nexport { useHandLayout } from './useHandLayout';\nexport { useIsMobile } from './useIsMobile';\nexport {\n  useInteractionMode,\n  type InteractionModeResult,\n} from './useInteractionMode';\n\nexport type { LobbyState } from './useLobby';\nexport type { Player } from './useMe';\nexport type { HistoryState, HistoryEntrySummary } from './useHistory';\nexport type {\n  UseHandLayoutOptions,\n  UseHandLayoutReturn,\n  CardPositionProps,\n  CardSize,\n  HandLayout,\n} from './useHandLayout';\n// Board primitive hooks (SDK v0.2.0+)\n// These utility hooks work with any data you provide\nexport { useNetworkGraph, type NetworkGraphApi } from './useNetworkGraph';\nexport {\n  useHexGrid,\n  type HexTileData,\n  type UseHexGridReturn,\n} from './useHexGrid';\nexport {\n  useSquareGrid,\n  type GridPieceData,\n  type CellData,\n  type DistanceType,\n  type NeighborType,\n  type UseSquareGridOptions,\n  type UseSquareGridReturn,\n} from './useSquareGrid';\nexport { useZoneMap, type UseZoneMapReturn } from './useZoneMap';\nexport { useSlotSystem, type SlotSystemApi } from './useSlotSystem';\n\n// Board state hooks (SDK v0.3.0+)\n// These hooks fetch board data from game state and provide query utilities\nexport {\n  useHexBoard,\n  useHexBoardOptional,\n  useHexBoardIds,\n  normalizeEdgeId,\n  normalizeVertexId,\n  type UseHexBoardReturn,\n} from './useHexBoard';\nexport {\n  useNetworkBoard,\n  useNetworkBoardOptional,\n  useNetworkBoardIds,\n  normalizeNetworkEdgeId,\n  type UseNetworkBoardReturn,\n} from './useNetworkBoard';\nexport {\n  useSquareBoard,\n  useSquareBoardOptional,\n  useSquareBoardIds,\n  type UseSquareBoardReturn,\n} from './useSquareBoard';\nexport {\n  useTrackBoard,\n  useTrackBoardIds,\n  type UseTrackBoardReturn,\n} from './useTrackBoard';\n\n// Dice hooks (SDK v0.4.0+)\nexport {\n  useDie,\n  useDice,\n  useAllDice,\n  useDiceIds,\n  type UseDieReturn,\n  type UseDiceReturn,\n  type UseAllDiceReturn,\n} from './useDice';\n",
