      "/**\n * @dreamboard/ui-sdk\n *\n * UI SDK for building dreamboard game plugins.\n * This package provides types, hooks, utilities, and UI components for\n * LLM-generated UI code running in sandboxed iframes.\n */\n\n// Core types\nexport type {\n  RuntimeAPI,\n  PluginSessionState,\n  ValidationResult,\n} from './types/runtime-api';\n\nexport type { PluginContext } from './types/plugin-context';\n\n// Plugin state types (new state-sync architecture)\nexport type {\n  GameState,\n  LobbyState,\n  Notification,\n  NotificationType,\n  NotificationPayload,\n  YourTurnPayload,\n  ActionRejectedPayload,\n  TurnChangedPayload,\n  GameEndedPayload,\n  ErrorPayload,\n  PluginStateSnapshot,\n  StateSyncMessage,\n  StateAckMessage,\n} from './types/plugin-state';\n\n// Board state types (for rendering game boards)\nexport type {\n  CardInfo,\n  PublicHandsByPlayerId,\n  PublicHandsByHandId,\n  BoardStates,\n  DiceStates,\n  HexBoardState,\n  HexTileState,\n  HexEdgeState,\n  HexVertexState,\n  NetworkBoardState,\n  NetworkNodeState,\n  NetworkEdgeState,\n  NetworkPieceState,\n  SquareBoardState,\n  SquareCellState,\n  SquarePieceState,\n  TrackBoardState,\n  TrackSpaceState,\n  TrackPieceState,\n  DieState,\n} from './types/player-state';\n\n// Plugin state context (new state-sync architecture)\nexport {\n  PluginStateProvider,\n  usePluginStateSnapshot,\n  usePluginState,\n  usePluginActions,\n} from './context/PluginStateContext';\nexport type { PluginStateProviderProps } from './context/PluginStateContext';\n",
