      '/**\n * Theme and styling types\n */\n\n/**\n * Color scheme configuration\n */\nexport interface ColorScheme {\n  /** Primary brand color */\n  primary?: string;\n  /** Secondary/accent color */\n  secondary?: string;\n  /** Accent color */\n  accent?: string;\n  /** Background color */\n  background?: string;\n  /** Foreground/text color */\n  foreground?: string;\n  /** Muted/secondary text color */\n  muted?: string;\n  /** Border color */\n  border?: string;\n  /** Success state color */\n  success?: string;\n  /** Warning state color */\n  warning?: string;\n  /** Error state color */\n  error?: string;\n  /** Info state color */\n  info?: string;\n}\n\n/**\n * Font configuration\n */\nexport interface FontScheme {\n  /** Base font family */\n  family?: string;\n  /** Base font size */\n  size?: string;\n  /** Heading font family */\n  headingFamily?: string;\n  /** Monospace font family */\n  monoFamily?: string;\n}\n\n/**\n * Complete theme configuration\n */\nexport interface ThemeConfig {\n  colors?: ColorScheme;\n  fonts?: FontScheme;\n}\n\n/**\n * Predefined theme presets\n */\nexport type ThemePreset = "classic" | "modern" | "minimal";\n',
